head.script:
//전역변수
scwin.login                     = $c.data.getMemInfo();
scwin.parentFrame               = $c.win.getParent();
scwin.pos_groupCode             = 0;
scwin.vUserHomeClsCd            = scwin.login.userHomeClsCd;
scwin.vSysAdminYn               = scwin.login.sysAdminYn;
// scwin.vEqCd                     = "" // 테스트용
scwin.vEqCd                     = scwin.parentFrame.scwin.eqCd == null ? "" : scwin.parentFrame.scwin.eqCd;
scwin.curDate                   = WebSquare.date.getCurrentServerDate();

//hidden
scwin.txt_clntNoValChk          = "";
scwin.txt_eqCd                  = "0";
scwin.txt_qryCond               = "0";
scwin.txt_sysCls                = "0";
scwin.txt_payIdx                = "";
scwin.txt_createYn              = "0";
scwin.txt_updateYn              = "0";
scwin.txt_rowCount              = "";
scwin.txt_saveType              = "";
scwin.data                      = "";


// 부산로컬권역
var vCBDataL = $c.gus.gauceUtil("getLuxeComboData","DsCommonEBC","retriveWrkDistrictCdCombo", ["PLO"])
//부산매입권역
var vCBDataM = $c.gus.gauceUtil("getLuxeComboData","DsCommonEBC","retriveWrkDistrictCdCombo", ["PEX"])
//복화권역
var vCBDataC = $c.gus.gauceUtil("getLuxeComboData","DsCommonEBC","retriveWrkDistrictCdCombo", ["CMP"])
//벌크작업권역
