//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "ZZ205", compID : "gr_logisticsMcarConsignment:eqHomeClsCd" },
        { grpCd : "OP190", compID : "acb_cargoClsCd" },
        { grpCd : "ZZ307", compID : "acb_wrkDstCd" },
        { grpCd : "ZZ202", compID : "acb_eqClssCd", opt : {'range': '2,DS'} },
    ];
    $c.data.setCommonCode(codeOptions);

    const param= [
        {
            method: "getLuxeComboData",
            param1: "DsCommonEBC",
            param2: "retriveWrkDistrictCdCombo",
            compID: "acb_logisWrkDistrictCd"
        }
    ];
    $c.data.setGauceUtil(param);
};

scwin.onUdcCompleted = function() {
    $c.sbm.execute(sbm_lobran);

    scwin.f_ContentsDisable();
    acb_qryCond.setValue("2");
    scwin.txt_payIdx = 1;
    acb_sysCls.setValue("LO")
    //부모에서도 파라미터로 해당 전역변수에 넣음.
    // if(scwin.vEqCd.trim()!= ""){
    //     lux_qryCond.Index = 1;
    //     ed_qryCntn.setValue(scwin.vEqCd);

    //     scwin.f_Retrieve();

    // }
    // if(scwin.vSysAdminYn == "1" || scwin.vUserHomeClsCd =="DS"){
    //     $c.gus.cfDisableBtn([b_Cancel,btn_save,b_Cancel1,btn_save1])
    // }else{
    //     $c.gus.cfDisableAllBtn();
    // }

    scwin.f_retrieveWrkDistrict(); // 작업권역 기본 로드

    ed_qryCntn.focus();

};


//-------------------------------------------------------------------------
// 물류자차위수탁 장비 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {  

    scwin.txt_saveType = "2";  // 0:신규, 1:수정, 2:조회


        let txt_qryCntn = ed_qryCntn.getValue().trimAll();

    if(txt_qryCntn.length < 1 ) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_011.replace("%1", "검색어").replace("%2", "글자(숫자) 한(두)"));
        ed_qryCntn.focus();
        return false;
    }

    let vEqDelYn = "0";
    let vMbssysVehclYn = "0";

    if(cbx_eqDelYn.getValue() == "1"){
        vEqDelYn = "1";
    }

    if(cbx_mbssysVehclYn.getValue() == "1"){
        vMbssysVehclYn = "1";
    }
    ds_logisticsMcarConsignment.reform();

    let condition = "?";
    condition += "sysCls=" + acb_sysCls.getValue()
        + "&qryCond=" + acb_qryCond.getValue()
        + "&eqClssCd=" + acb_eqClssCd.getValue()
        + "&qryCntn=" + ed_qryCntn.getValue()
        + "&eqDelYn=" + vEqDelYn
        + "&mbssysVehclYn=" + vMbssysVehclYn;

        sbm_searchLogisticsMcarConsignment.action = "/cm.bc.eq.eqmgnt.cmd.RetrieveLogisticsMcarConsignmentEquipmentListCMD.do" + condition; 
        $c.sbm.execute(sbm_searchLogisticsMcarConsignment);

        scwin.f_ContentsDisable();

        // $c.gus.cfDisableBtn([b_Cancel,btn_save,b_Cancel1,btn_save1])

}


//-------------------------------------------------------------------------
// 항목 Enable
