    $c.gus.cfEnableObj(ed_hwajong1Cd, true); 
    $c.gus.cfEnableObj(ed_hwajong1Nm, true); 
    $c.gus.cfEnableObj(ed_hwajong2Cd, true); 
    $c.gus.cfEnableObj(ed_hwajong2Nm, true); 
    $c.gus.cfEnableObj(ed_hwajong3Cd, true); 
    $c.gus.cfEnableObj(ed_hwajong3Nm, true); 
    $c.gus.cfEnableObj(ed_hwajong4Cd, true); 
    $c.gus.cfEnableObj(ed_hwajong4Nm, true); 
    // 링크 이미지 활성화

    $c.gus.cfEnableObj(mbssysDt_search, true); // 회원제계약기간조회 
    $c.gus.cfEnableObj(bondTransdt_search, true); // 보세운송차량 조회 
    $c.gus.cfEnableObj(ica_eqChgDt, true); // 장비변경일자 조회 

    // LuxCombo  활성화
    $c.gus.cfEnableObj(acb_wrkDstCd, true); // 작업구간
    $c.gus.cfEnableObj(acb_cargoClsCd, true); //화물구분
    $c.gus.cfEnableObj(rd_mobileIndictYn, true); //모바일지시여부
    $c.gus.cfEnableObj(rd_mbssysVehclYn, true); //회원제차량여부
    $c.gus.cfEnableObj(acb_logisWrkDistrictCd, true); //작업권역

    $c.gus.cfEnableObj(rd_eqDelYn, false); // 장비사용여부
    $c.gus.cfEnableObj(acb_co_lc_srchLobran, true);

    $c.gus.cfEnableObj(rd_bulkCmpsTcrgYn, false); //벌크복화여부
    $c.gus.cfEnableObj(bulkCmpsTcrgDt, false);     //복화 기간
}

