                                    ,null					
                                    ,null		
                                    ,null			
                                    ,null				
                                    ,pAllSearch			
                                    ,"화종구분조회,화종구분코드,화종구분명"); 

                                        //화종구분코드          화종구분명
            // cfSetReturnValue(rtnList, ed_hwajong2Cd, ed_hwajong2Nm);
