// ======================
// 콜백 함수들
// ======================
scwin.udc_hwajongInfo1_callBackFunc = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_hwajong1Cd.setValue(rtnList[0]);
        ed_hwajong1Nm.setValue(rtnList[1]);
        ed_hwajong1Cd.options.hidVal = rtnList[0];
        ed_hwajong1Nm.options.hidVal = rtnList[1];
    } else {
        ed_hwajong1Cd.setValue("");
        ed_hwajong1Nm.setValue("");
        ed_hwajong1Cd.options.hidVal = "";
        ed_hwajong1Nm.options.hidVal = "";
    }
};

