//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = async function () {

    if(ds_logisticsMcarConsignment.getRowCount() <1){
        await $c.win.alert("수정할 장비정보를 먼저 조회해 주십시오.");
        ed_qryCntn.focus();
        return false;
    }

    let vRepstNm = ds_logisticsMcarConsignment.getCellData(ds_logisticsMcarConsignment.getRowPosition() ,"repstNm");
    let vLogisVehclDrvNm1 = ed_logisVehclDrvNm1.getValue();

    if(vLogisVehclDrvNm1==""){	
        ed_logisVehclDrvNm1.setValue(vRepstNm);
    }

    scwin.f_ContentsEnable();

    scwin.txt_updateYn = "1";   // 수정인경우
    scwin.txt_saveType = "1";  // 0:신규, 1:수정, 2:조회, 3:저장, 4:취소
    //	eqChgDt.setValue(curDate);		// 장비변경일자

    // $c.gus.cfDisableBtn([$c.gus.getctrlBtn('b_Update')]);
}

//-------------------------------------------------------------------------
// 장비 등록, 수정 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {
    // 취소 확인
    scwin.f_ContentsDisable();

    if(ds_logisticsMcarConsignment.getRowPosition() > ds_logisticsMcarConsignment.getRowCount() || ds_logisticsMcarConsignment.getModifiedIndex().length > 0){
        ds_logisticsMcarConsignment.undoRow(ds_logisticsMcarConsignment.getRowPosition());
    }
    // $c.gus.cfDisableBtn([b_Cancel,btn_save,b_Cancel1,btn_save1])


    scwin.txt_saveType = "4";  // 0:신규, 1:수정, 2:조회, 3:저장, 4:취소
    ica_eqChgDt.setValue("");		// 장비변경일자
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {

    scwin.txt_saveType = "3"; // 타입이 저장

    // 필수항목 체크
    if(! await $c.gus.cfValidate([ica_eqChgDt])){
        return false;
    }


    // 벌크복화를 체크했으면 벌크복화기간을 입력해야한다.
    if(rd_bulkCmpsTcrgYn.getValue()==1){
        if(ed_bulkCmpsTcrgStDt.getValue() =="" || ed_bulkCmpsTcrgStDt.getValue().trim().length!=8)
        {$c.gus.cfAlertMsg("벌크복화여부를 체크하셨으면 "+MSG_CM_ERR_002,["벌크복화 시작일"]);
            ed_bulkCmpsTcrgStDt.focus();
            return;
        }
        if(ed_bulkCmpsTcrgEndDt.getValue() ==""  || ed_bulkCmpsTcrgEndDt.getValue().trim().length!=8)
        {$c.gus.cfAlertMsg("벌크복화여부를 체크하셨으면 "+MSG_CM_ERR_002,["벌크복화 종료일"]);
            ed_bulkCmpsTcrgEndDt.focus();
            return;
        }		
    }

    //변경한 데이터가 있는지 체크한다. 

    if(ds_logisticsMcarConsignment.getModifiedIndex().length > 0==false){
        await $c.win.alert("변경된 사항이 없습니다.");
        return;
    }      

    // 저장확인 
    if(await $c.win.confirm("저장하시겠습니까?")==true){
        pos_groupCode = ds_logisticsMcarConsignment.getRowPosition();

        let vCurrentRowVehclShortCd = ds_logisticsMcarConsignment.getCellData(ds_logisticsMcarConsignment.getRowPosition(), "vehclShortCd");

        acb_qryCond.setValue("2");
        ed_qryCntn.setValue(vCurrentRowVehclShortCd);

        sbm_saveLogisticsMcarConsignment.action ="/cm.bc.eq.eqmgnt.cmd.UpdateLogisticsMcarConsignmentEquipmentInformationCMD.do";
        $c.sbm.execute(sbm_saveLogisticsMcarConsignment);  

    }

};

//-------------------------------------------------------------------------
// 행취소
//-------------------------------------------------------------------------
scwin.f_Undo = function(){

    ds_logisticsMcarConsignment.undoRow(ds_logisticsMcarConsignment.getRowPosition());
}


