//-------------------------------------------------------------------------
// 권역콤보
// gubun = L : 부산로컬권역,  M : 부산매입권역,  C : 복화작업권역  , B : 벌크작업권역 
//-------------------------------------------------------------------------

scwin.f_districtSearch = async function(gubun, rowIdx) {
    if (gubun == "L") {
        dlt_gauceUtil_acb_logisWrkDistrictCd.setJSON(vCBDataL, false);
        // acb_logisWrkDistrictCd.setNodeSet(vCBDataL);
        // acb_logisWrkDistrictCd.setRef(ds_logisticsMcarConsignment) = vCBDataL;
    } else if (gubun == "M") {
        dlt_gauceUtil_acb_logisWrkDistrictCd.setJSON(vCBDataM, false);
        // acb_logisWrkDistrictCd.setNodeSet(vCBDataM)
        // acb_logisWrkDistrictCd.setRef(ds_logisticsMcarConsignment) = vCBDataM;

    } else if (gubun == "C") {
        dlt_gauceUtil_acb_logisWrkDistrictCd.setJSON(vCBDataC, false);
        // acb_logisWrkDistrictCd.setNodeSet(vCBDataC)
        // acb_logisWrkDistrictCd.setRef(ds_logisticsMcarConsignment) = vCBDataC;

    } else if (gubun == "B") {	
        dlt_gauceUtil_acb_logisWrkDistrictCd.setJSON(vCBDataB, false);
        // acb_logisWrkDistrictCd.setNodeSet(vCBDataB)
        // acb_logisWrkDistrictCd.setRef(ds_logisticsMcarConsignment) = vCBDataB;
    }
};

scwin.f_afterDistrictSearch = async function(gubun, rowIdx){
    await scwin.f_districtSearch(gubun, rowIdx);
    acb_logisWrkDistrictCd.setValue(scwin.data);
}

//-------------------------------------------------------------------------
// 작업권역콤보 
//-------------------------------------------------------------------------

scwin.f_retrieveWrkDistrict = function (info) {
    let rowIdx = ds_logisticsMcarConsignment.getRowPosition()
    if (info){
        rowIdx = info.newRowIndex;
    }
    scwin.data = ds_logisticsMcarConsignment.getCellData(rowIdx, "logisWrkDistrictCd")
}

