scwin.f_toExcel1 = async function () {
    if (ds_logisticsMcarConsignment.getRowCount() == 0) {
        await $c.win.alert("물류중기 목록이 없습니다.");
        return;
    }

    let fileName = '물류중기목록';
    let sheetTitle = '물류중기목록';

    if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
        await $c.data.downloadGridViewExcel(gr_logisticsMcarConsignment, { fileName: fileName + ".xlsx", sheetName: sheetTitle, });
    }
};

