scwin.sbm_saveLogisticsMcarConsignment_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
	await $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다

	scwin.f_ContentsDisable();
    ds_logisticsMcarConsignment.reform();
    // scwin.f_Retrieve();
	// $c.gus.cfDisableBtn([$c.gus.getctrlBtn('b_Cancel', 'btn_save')]);
};



scwin.sbm_searchLogisticsMcarConsignment_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    let rowCnt = ds_logisticsMcarConsignment.getRowCount();

    if (rowCnt == 0) {
        await $c.win.alert("조회된 데이터가 없습니다.");
        ed_qryCntn.focus();
        return;
    }

    if(scwin.vSysAdminYn== "0" && scwin.vUserHomeClsCd !="DS"){
        $c.gus.cfDisableAllBtn();
    }

    $c.gus.cfGoPrevPosition(gr_logisticsMcarConsignment, scwin.pos_groupCode);
    // gr_logisticsMcarConsignment.setFocusedCell(0, 0);
    totalRows.setValue(rowCnt);
    scwin.f_retrieveWrkDistrict();
};


scwin.acb_wrkDstCd_onchange = function (info) {
    scwin.f_retrieveWrkDistrict();
};



