scwin.ds_logisticsMcarConsignment_onrowpositionchange = async function (info) {
    let rowIdx = gr_logisticsMcarConsignment.getFocusedRowIndex()
    let vAssgnLobranCd = ds_logisticsMcarConsignment.getCellData(rowIdx, "assgnLobranCd");  // 배정점소
    let vCargoClsCd = ds_logisticsMcarConsignment.getCellData(rowIdx, "cargoClsCd")         // 화물구분
    let vWrkDstCd = ds_logisticsMcarConsignment.getCellData(rowIdx, "wrkDstCd")             // 작업구간


    if(vAssgnLobranCd=="6AA" && vCargoClsCd=="C"){   // 배정점소가 부산지점이면서 화물구분이 컨테이너인 경우

            if(vWrkDstCd=="L"){   
                // 작업구간이 로컬인 경우
            scwin.f_afterDistrictSearch("L", rowIdx);         //부산로컬권역

            }else if (vWrkDstCd=="S"){    // 셔틀 
            scwin.f_afterDistrictSearch("M", rowIdx);	       //부산매입권역   

            }else{		            
            scwin.f_afterDistrictSearch("C", rowIdx);	       //CMP : 컨테이너일 경우.   
            }

    }else if(vCargoClsCd=="B"){
        scwin.f_afterDistrictSearch("B", rowIdx);	       //BWK : 컨테이너일 경우.   

    }else if(vCargoClsCd=="C"){
        scwin.f_afterDistrictSearch("C", rowIdx);	       //CMP : 컨테이너일 경우.   
    }
    else{
        scwin.f_afterDistrictSearch("A", rowIdx)
    }

    let vCountRow = ds_logisticsMcarConsignment.getRowCount();
    let vChgCount = 0;
    let vChgRow = 0;

    for(let i=0;i<=vCountRow;i++){
        let vCurRowStatus = ds_logisticsMcarConsignment.getRowStatus(i);

        if(vCurRowStatus=="C" || vCurRowStatus=="U"){
            vChgCount++;
            vChgRow = i;
        }
    }

    if(vChgCount>0 && info.newRowIndex!=vChgRow){
            await $c.win.alert("장비 신규등록이나 변경사항을 저장하신 후에 다른 장비정보로 이동하실수 있습니다.");
            ds_logisticsMcarConsignment.setRowPosition(vChgRow);
            gr_logisticsMcarConsignment.setFocusedCell(vChgRow, 0);
            return;
    }
};
